woodmartThemeModule.updateAjaxDeliveryDates=function(){var e=document.querySelector(".wd-est-del");e&&jQuery.ajax({url:woodmart_settings.ajaxurl,data:{action:"woodmart_update_delivery_dates",product_id:e.dataset.productId},dataType:"json",method:"GET",success:function(e){e.hasOwnProperty("fragments")&&Object.keys(e.fragments).forEach(function(t){var o=e.fragments[t];document.querySelectorAll(t).forEach(function(e){e.innerHTML=o,o?e.parentNode.classList.remove("wd-hide"):e.parentNode.classList.add("wd-hide")})})},error:function(){console.error("Something wrong with AJAX response. Probably some PHP conflict.")},complete:function(){e.classList.add("wd-loaded")}})},window.addEventListener("load",function(){woodmartThemeModule.updateAjaxDeliveryDates()});